import { RowSelectionState } from '@tanstack/react-table';
import { isEmpty } from 'lodash';
import { useCallback, useMemo, useState } from 'react';

export function useRowSelection() {
  const [rowSelection, setRowSelection] = useState<RowSelectionState>({});

  const clearRowSelection = useCallback(() => {
    setRowSelection({});
  }, []);

  const selectedCount = useMemo(() => {
    return Object.values(rowSelection).filter(Boolean).length;
  }, [rowSelection]);

  return {
    rowSelection,
    setRowSelection,
    rowSelectionIsEmpty: isEmpty(rowSelection),
    clearRowSelection,
    selectedCount,
  };
}

export type UseRowSelectionType = ReturnType<typeof useRowSelection>;

export function useSelectedIds<T extends Array<{ id: string }> | undefined>(
  rowSelection: RowSelectionState,
  list?: T,
) {
  const selectedIds = useMemo(
    () =>
      Object.keys(rowSelection).filter((key) => {
        const value = rowSelection[key];
        return value === true;
      }),
    [rowSelection],
  );

  const selectedItems = useMemo(() => {
    if (!list || selectedIds.length === 0) {
      return [];
    }
    const idSet = new Set(selectedIds);
    return list.filter((item) => idSet.has(item.id));
  }, [list, selectedIds]);

  return { selectedIds, selectedItems };
}
